class AgentError:
    """Why an agent-resource call failed."""
    pass

class AgentError_NoSessionConfigured(AgentError, _WitVariantCase):
    """The agent was constructed without a session config."""
    tag = 'no-session-configured'

class AgentError_Storage(AgentError, _WitVariantCase):
    """The storage backend rejected the operation."""
    tag = 'storage'

class AgentError_InvalidInput(AgentError, _WitVariantCase):
    """Supplied payload did not match the expected shape."""
    tag = 'invalid-input'

class AgentError_UnknownInterrupt(AgentError, _WitVariantCase):
    """Supplied `interrupt-id` does not match any live interrupt."""
    tag = 'unknown-interrupt'

class AgentError_Internal(AgentError, _WitVariantCase):
    """Catch-all for internal failures."""
    tag = 'internal'

_AgentError_CASES: dict[str, type] = {
    'no-session-configured': AgentError_NoSessionConfigured,
    'storage': AgentError_Storage,
    'invalid-input': AgentError_InvalidInput,
    'unknown-interrupt': AgentError_UnknownInterrupt,
    'internal': AgentError_Internal,
}

def _AgentError_lift(raw: _WitVariant) -> AgentError:
    cls = _AgentError_CASES.get(raw.tag)
    if cls is None:
        raise ValueError(f'unknown AgentError arm: {raw.tag!r}')
    return cls(raw.payload)
AgentError.lift = staticmethod(_AgentError_lift)  # type: ignore[attr-defined]

class Agent:
    """An agent instance. Persistent across `generate` calls."""
    # Wraps a wasmtime-py ResourceAny / ResourceHost handle.
    # The runtime sets ._handle to the underlying resource and
    # ._invoke to a callable that dispatches a method by WIT name.

    def __init__(self, handle: Any, invoke: Any = None) -> None:
        self._handle = handle
        self._invoke = invoke

    @staticmethod
    def new(config: AgentConfig, *, invoke: Any) -> 'Agent':
        return Agent(invoke('[constructor]agent', (config,)), invoke)

    def generate(self, args: InvokeArgs) -> Any:
        return self._invoke('[method]agent.generate', (self._handle, args,))

    def get_messages(self) -> list[Message]:
        return self._invoke('[method]agent.get-messages', (self._handle,))

    def set_messages(self, messages: list[Message]) -> Any:
        return self._invoke('[method]agent.set-messages', (self._handle, messages,))

    def get_app_state(self) -> str:
        return self._invoke('[method]agent.get-app-state', (self._handle,))

    def set_app_state(self, json: str) -> Any:
        return self._invoke('[method]agent.set-app-state', (self._handle, json,))

    def get_model_state(self) -> str:
        return self._invoke('[method]agent.get-model-state', (self._handle,))

    def set_model_state(self, json: str) -> Any:
        return self._invoke('[method]agent.set-model-state', (self._handle, json,))

    def get_traces(self) -> list[AgentTrace]:
        return self._invoke('[method]agent.get-traces', (self._handle,))

    def get_metrics(self) -> AgentMetrics:
        return self._invoke('[method]agent.get-metrics', (self._handle,))

    def save_session(self) -> Any:
        return self._invoke('[method]agent.save-session', (self._handle,))

    def list_snapshots(self) -> Any:
        return self._invoke('[method]agent.list-snapshots', (self._handle,))

    def delete_session(self) -> Any:
        return self._invoke('[method]agent.delete-session', (self._handle,))


